  1→#!/usr/bin/env bun
  2→
  3→import { readdir, mkdir, cp, rm, stat, readFile, writeFile } from "node:fs/promises";
  4→import { join, dirname, resolve } from "node:path";
  5→import { tmpdir } from "node:os";
  6→import { mkdtemp } from "node:fs/promises";
  7→import { existsSync } from "node:fs";
  8→
  9→// Construct installer — deploys from repo to ~/.claude
 10→// Source: construct/ (modules), dotclaude/ (CLAUDE.md, settings.json, commands)
 11→// Preserves: ALL CAPS files in identity/, sessions/, ratings.jsonl
 12→// Overwrites: hooks, skills, meta, commands, settings, CLAUDE.md
 13→
 14→const REPO = dirname(resolve(Bun.argv[1]));
 15→const CONSTRUCT_SRC = join(REPO, "construct");
 16→const TEMPLATES = join(REPO, "dotclaude");
 17→const DST = join(Bun.env.HOME!, ".claude");
 18→
 19→const INFRA_FILES = new Set(["README.md", "INSTALL.md"]);
 20→
 21→// Static preserved paths (relative to construct/)
 22→const PRESERVE = [
 23→  "memory/signals/ratings.jsonl",
 24→  "memory/sessions",
 25→];
 26→
 27→// File extensions that should never be overwritten during sync (runtime data)
 28→const SKIP_EXTENSIONS = [".db", ".db-wal", ".db-shm"];
 29→
 30→const BACKUP_DIR = join(DST, "construct", "data", "backups");
 31→const MAX_BACKUPS = 5;
 32→
 33→/** Back up the DB before install, keeping the last N backups */
 34→async function backupDb(): Promise<void> {
 35→  const dbPath = join(DST, "construct", "data", "construct.db");
 36→  if (!(await exists(dbPath))) return;
 37→
 38→  await mkdir(BACKUP_DIR, { recursive: true });
 39→  const ts = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
 40→  await cp(dbPath, join(BACKUP_DIR, `construct-${ts}.db`));
 41→
 42→  // Copy WAL if present (ensures consistent backup)
 43→  const walPath = dbPath + "-wal";
 44→  if (await exists(walPath)) {
 45→    await cp(walPath, join(BACKUP_DIR, `construct-${ts}.db-wal`));
 46→  }
 47→
 48→  console.log(`  backed up: construct-${ts}.db`);
 49→
 50→  // Prune old backups, keep last N
 51→  const files = (await readdir(BACKUP_DIR))
 52→    .filter((f) => f.startsWith("construct-") && f.endsWith(".db"))
 53→    .sort()
 54→    .reverse();
 55→
 56→  for (const f of files.slice(MAX_BACKUPS)) {
 57→    const stem = f.replace(/\.db$/, "");
 58→    await rm(join(BACKUP_DIR, f), { force: true });
 59→    await rm(join(BACKUP_DIR, stem + ".db-wal"), { force: true });
 60→    await rm(join(BACKUP_DIR, stem + ".db-shm"), { force: true });
 61→  }
 62→}
 63→
 64→/** Discover ALL CAPS .md data files in a directory (stem is [A-Z_]+ only) */
 65→async function discoverAllCapsMd(dir: string): Promise<string[]> {
 66→  if (!existsSync(dir)) return [];
 67→  const entries = await readdir(dir);
 68→  return entries.filter((f) => {
 69→    if (!f.endsWith(".md")) return false;
 70→    if (INFRA_FILES.has(f)) return false;
 71→    const stem = f.slice(0, -3);
 72→    return /^[A-Z_]+$/.test(stem);
 73→  });
 74→}
 75→
 76→/** Check if path exists */
 77→async function exists(path: string): Promise<boolean> {
 78→  try {
 79→    await stat(path);
 80→    return true;
 81→  } catch {
 82→    return false;
 83→  }
 84→}
 85→
 86→/** Sync srcDir to dstDir: copy everything from src, delete files in dst not in src */
 87→async function syncDir(srcDir: string, dstDir: string): Promise<void> {
 88→  await mkdir(dstDir, { recursive: true });
 89→
 90→  // Collect all relative paths in src
 91→  const srcPaths = new Set<string>();
 92→  const SKIP_DIRS = new Set(["node_modules", "dist", ".bun", "backups"]);
 93→  async function walk(dir: string, rel: string) {
 94→    const entries = await readdir(dir, { withFileTypes: true });
 95→    for (const e of entries) {
 96→      const relPath = rel ? `${rel}/${e.name}` : e.name;
 97→      if (e.isDirectory()) {
 98→        if (SKIP_DIRS.has(e.name)) continue;
 99→        srcPaths.add(relPath);
100→        await walk(join(dir, e.name), relPath);
101→      } else {
102→        srcPaths.add(relPath);
103→      }
104→    }
105→  }
106→  await walk(srcDir, "");
107→
108→  // Copy all from src to dst, skipping node_modules/dist/.bun and DB files
109→  await cp(srcDir, dstDir, {
110→    recursive: true,
111→    force: true,
112→    filter: (src) => {
113→      const base = src.split("/").pop()!;
114→      if (SKIP_DIRS.has(base)) return false;
115→      if (SKIP_EXTENSIONS.some((ext) => base.endsWith(ext))) return false;
116→      return true;
117→    },
118→  });
119→
120→  // Delete files in dst not in src
121→  async function cleanDst(dir: string, rel: string) {
122→    if (!(await exists(dir))) return;
123→    const entries = await readdir(dir, { withFileTypes: true });
124→    for (const e of entries) {
125→      const relPath = rel ? `${rel}/${e.name}` : e.name;
126→      if (!srcPaths.has(relPath) && !SKIP_DIRS.has(e.name) && !SKIP_EXTENSIONS.some((ext) => e.name.endsWith(ext))) {
127→        await rm(join(dir, e.name), { recursive: true, force: true });
128→      } else if (e.isDirectory()) {
129→        await cleanDst(join(dir, e.name), relPath);
130→      }
131→    }
132→  }
133→  await cleanDst(dstDir, "");
134→}
135→
136→// --- Main ---
137→
138→console.log("=== Construct Installer ===");
139→console.log(`src: ${REPO}`);
140→console.log(`dst: ${DST}`);
141→console.log();
142→
143→// 1. Back up preserved files to temp dir
144→console.log("backing up preserved files...");
145→const backupDir = await mkdtemp(join(tmpdir(), "construct-backup-"));
146→
147→try {
148→  for (const rel of PRESERVE) {
149→    const src = join(DST, "construct", rel);
150→    if (await exists(src)) {
151→      const dst = join(backupDir, rel);
152→      await mkdir(dirname(dst), { recursive: true });
153→      await cp(src, dst, { recursive: true });
154→    }
155→  }
156→
157→  // Back up ALL CAPS .md files from identity/ and memory/
158→  await mkdir(join(backupDir, "core/identity"), { recursive: true });
159→  await mkdir(join(backupDir, "memory"), { recursive: true });
160→
161→  for (const f of await discoverAllCapsMd(join(DST, "construct/core/identity"))) {
162→    await cp(join(DST, "construct/core/identity", f), join(backupDir, "core/identity", f));
163→    console.log(`  preserved: core/identity/${f}`);
164→  }
165→
166→  for (const f of await discoverAllCapsMd(join(DST, "construct/memory"))) {
167→    await cp(join(DST, "construct/memory", f), join(backupDir, "memory", f));
168→    console.log(`  preserved: memory/${f}`);
169→  }
170→
171→  // 2. Sync construct/ tree (delete stale files, overwrite everything)
172→  // 2a. Back up DB before sync
173→  console.log("backing up database...");
174→  await backupDb();
175→
176→  //    DB files (*.db, *.db-wal, *.db-shm) are never overwritten
177→  console.log("syncing construct/...");
178→  await syncDir(CONSTRUCT_SRC, join(DST, "construct"));
179→
180→  // 3. Restore preserved files from temp dir
181→  console.log("restoring preserved files...");
182→
183→  for (const rel of PRESERVE) {
184→    const backup = join(backupDir, rel);
185→    if (await exists(backup)) {
186→      const target = join(DST, "construct", rel);
187→      await mkdir(dirname(target), { recursive: true });
188→      await rm(target, { recursive: true, force: true });
189→      await cp(backup, target, { recursive: true });
190→    }
191→  }
192→
193→  // Restore ALL CAPS .md files
194→  for (const [subdir, target] of [
195→    ["core/identity", join(DST, "construct/core/identity")],
196→    ["memory", join(DST, "construct/memory")],
197→  ]) {
198→    const backupSub = join(backupDir, subdir);
199→    if (await exists(backupSub)) {
200→      for (const f of await readdir(backupSub)) {
201→        if (f.endsWith(".md")) {
202→          const src = join(backupSub, f);
203→          const dst = join(target, f);
204→          await cp(src, dst);
205→          // Verify byte-size matches
206→          const srcSize = (await stat(src)).size;
207→          const dstSize = (await stat(dst)).size;
208→          if (srcSize !== dstSize) {
209→            console.error(`  ✗ size mismatch: ${f} (${srcSize} → ${dstSize})`);
210→          }
211→        }
212→      }
213→    }
214→  }
215→
216→  // 4. Sync commands — install from repo, remove stale Construct-owned commands
217→  console.log("syncing commands...");
218→  await mkdir(join(DST, "commands"), { recursive: true });
219→
220→  const cmdDir = join(TEMPLATES, "commands");
221→  const repoCommands = new Set<string>();
222→  if (await exists(cmdDir)) {
223→    for (const f of await readdir(cmdDir)) {
224→      if (f.endsWith(".md")) {
225→        await cp(join(cmdDir, f), join(DST, "commands", f));
226→        repoCommands.add(f);
227→      }
228→    }
229→  }
230→  console.log(`  installed: ${repoCommands.size ? [...repoCommands].join(" ") : "none"}`);
231→
232→  // Remove known Construct commands that are no longer in the repo
233→  const CONSTRUCT_COMMANDS = ["construct.md", "verify.md", "install.md", "test.md",
234→    "worktree.md", "grasp.md", "status.md", "retain.md", "common-ground.md", "dashboard.md",
235→    "goal.md", "todo.md", "finish.md"];
236→  for (const f of CONSTRUCT_COMMANDS) {
237→    if (!repoCommands.has(f) && await exists(join(DST, "commands", f))) {
238→      await rm(join(DST, "commands", f));
239→      console.log(`  removed stale: ${f}`);
240→    }
241→  }
242→
243→  // 5. Merge settings.json — replace hooks + statusLine, preserve everything else
244→  console.log("merging settings.json...");
245→
246→  const repoSettings = JSON.parse(await readFile(join(TEMPLATES, "settings.json"), "utf-8"));
247→  // Path fixup: rewrite relative paths in hook commands to absolute $HOME-based paths
248→  const home = Bun.env.HOME!;
249→  function fixPaths(obj: any): any {
250→    if (typeof obj === "string") {
251→      return obj.replace(/^(bun|bash) construct\//, `$1 ${home}/.claude/construct/`);
252→    }
253→    if (Array.isArray(obj)) return obj.map(fixPaths);
254→    if (obj && typeof obj === "object") {
255→      const out: any = {};
256→      for (const [k, v] of Object.entries(obj)) out[k] = fixPaths(v);
257→      return out;
258→    }
259→    return obj;
260→  }
261→  const fixedSettings = fixPaths(repoSettings);
262→
263→  const dstSettingsPath = join(DST, "settings.json");
264→  if (await exists(dstSettingsPath)) {
265→    const existingSettings = JSON.parse(await readFile(dstSettingsPath, "utf-8"));
266→    const merged = {
267→      ...existingSettings,
268→      hooks: fixedSettings.hooks,
269→      statusLine: fixedSettings.statusLine,
270→    };
271→    await writeFile(dstSettingsPath, JSON.stringify(merged, null, 2) + "\n");
272→  } else {
273→    await writeFile(dstSettingsPath, JSON.stringify(fixedSettings, null, 2) + "\n");
274→  }
275→
276→  // 6. Update CLAUDE.md — replace # Construct section, preserve content before AND after
277→  console.log("updating CLAUDE.md...");
278→  const rawSection = await readFile(join(TEMPLATES, "CLAUDE.md"), "utf-8");
279→  // Strip source-only HTML comments — they're meaningless in the installed copy
280→  const constructSection = rawSection.replace(/<!--[\s\S]*?-->\s*/g, "");
281→  const dstClaudeMd = join(DST, "CLAUDE.md");
282→
283→  if (await exists(dstClaudeMd)) {
284→    const content = await readFile(dstClaudeMd, "utf-8");
285→    const lines = content.split("\n");
286→
287→    // Find the start of "# Construct"
288→    const startIdx = lines.findIndex((l) => /^# Construct\s*$/.test(l));
289→
290→    if (startIdx !== -1) {
291→      // Find the end: next ^# heading at same level (single #), or EOF
292→      let endIdx = lines.length;
293→      for (let i = startIdx + 1; i < lines.length; i++) {
294→        if (/^# [^\s#]/.test(lines[i]) || /^# $/.test(lines[i])) {
295→          endIdx = i;
296→          break;
297→        }
298→      }
299→
300→      // Clean stale Construct source comments from the user section
301→      const before = lines.slice(0, startIdx).join("\n")
302→        .replace(/<!--\s*SOURCE FILE[^>]*?-->\s*/g, "");
303→      const after = lines.slice(endIdx).join("\n");
304→
305→      let result = "";
306→      if (before.trim()) {
307→        result = before.replace(/\n+$/, "") + "\n\n";
308→      }
309→      result += constructSection.replace(/\n+$/, "");
310→      if (after.trim()) {
311→        result += "\n\n" + after.replace(/^\n+/, "");
312→      }
313→      result += "\n";
314→
315→      await writeFile(dstClaudeMd, result);
316→    } else {
317→      // No existing Construct section — append
318→      const result = content.replace(/\n+$/, "") + "\n\n" + constructSection.replace(/\n+$/, "") + "\n";
319→      await writeFile(dstClaudeMd, result);
320→    }
321→  } else {
322→    await writeFile(dstClaudeMd, constructSection);
323→  }
324→
325→  // 7. Verify critical files — byte-size check on key infrastructure
326→  const criticalFiles = [
327→    "construct/skills/skill-rules.json",
328→    "construct/trace.ts",
329→    "construct/memory/parse-transcript.ts",
330→  ];
331→  let verifyFails = 0;
332→  for (const rel of criticalFiles) {
333→    const src = join(CONSTRUCT_SRC, rel.replace("construct/", ""));
334→    const dst = join(DST, rel);
335→    if (await exists(src) && await exists(dst)) {
336→      const srcSize = (await stat(src)).size;
337→      const dstSize = (await stat(dst)).size;
338→      if (srcSize !== dstSize) {
339→        console.error(`  ✗ size mismatch: ${rel} (src ${srcSize} → dst ${dstSize})`);
340→        verifyFails++;
341→      }
342→    }
343→  }
344→  if (verifyFails > 0) {
345→    console.error(`\n⚠ ${verifyFails} file(s) failed size verification`);
346→  }
347→
348→  console.log();
349→  console.log("done. run /verify to check installation.");
350→} finally {
351→  await rm(backupDir, { recursive: true, force: true });
352→}
