  1→import { nanoid } from 'nanoid';
  2→import { eq, and, lte, isNull, sql, desc } from 'drizzle-orm';
  3→import type { Db } from '@construct/data';
  4→import { todos, goals } from '../schema.js';
  5→import { createTodoSchema, updateTodoSchema } from '../validators.js';
  6→import type { EventBus } from './event-bus.js';
  7→
  8→export function getTodosActive(db: Db) {
  9→  const today = new Date().toISOString().slice(0, 10);
 10→
 11→  const activeTodos = db
 12→    .select()
 13→    .from(todos)
 14→    .where(eq(todos.done, false))
 15→    .orderBy(todos.createdAt)
 16→    .all();
 17→
 18→  const completedToday = db
 19→    .select()
 20→    .from(todos)
 21→    .where(
 22→      and(
 23→        eq(todos.done, true),
 24→        sql`substr(${todos.updatedAt}, 1, 10) = ${today}`
 25→      )
 26→    )
 27→    .orderBy(desc(todos.updatedAt))
 28→    .all();
 29→
 30→  const allTodos = [...activeTodos, ...completedToday];
 31→  const goalIds = [...new Set(allTodos.map((t) => t.goalId).filter(Boolean))] as string[];
 32→
 33→  const goalTitles = new Map<string, string>();
 34→  for (const goalId of goalIds) {
 35→    const goal = db.select({ id: goals.id, title: goals.title }).from(goals).where(eq(goals.id, goalId)).get();
 36→    if (goal) goalTitles.set(goal.id, goal.title);
 37→  }
 38→
 39→  const enrichTodo = (t: typeof todos.$inferSelect) => ({
 40→    ...t,
 41→    goalTitle: t.goalId ? (goalTitles.get(t.goalId) ?? null) : null,
 42→  });
 43→
 44→  return {
 45→    active: activeTodos.map(enrichTodo),
 46→    completed: completedToday.map(enrichTodo),
 47→  };
 48→}
 49→
 50→export function getTodosForDay(db: Db, date: string) {
 51→  const undoneDue = db
 52→    .select()
 53→    .from(todos)
 54→    .where(and(eq(todos.done, false), lte(todos.dueDate, date)))
 55→    .all();
 56→
 57→  const undoneNoDue = db
 58→    .select()
 59→    .from(todos)
 60→    .where(
 61→      and(
 62→        eq(todos.done, false),
 63→        isNull(todos.dueDate),
 64→        lte(sql`substr(${todos.createdAt}, 1, 10)`, date)
 65→      )
 66→    )
 67→    .all();
 68→
 69→  const completedToday = db
 70→    .select()
 71→    .from(todos)
 72→    .where(
 73→      and(
 74→        eq(todos.done, true),
 75→        sql`substr(${todos.updatedAt}, 1, 10) = ${date}`
 76→      )
 77→    )
 78→    .all();
 79→
 80→  const undoneMap = new Map<string, typeof todos.$inferSelect>();
 81→  for (const t of [...undoneDue, ...undoneNoDue]) {
 82→    undoneMap.set(t.id, t);
 83→  }
 84→
 85→  const allTodos = [...undoneMap.values(), ...completedToday];
 86→  const goalIds = [...new Set(allTodos.map((t) => t.goalId).filter(Boolean))] as string[];
 87→
 88→  const goalTitles = new Map<string, string>();
 89→  for (const goalId of goalIds) {
 90→    const goal = db.select({ id: goals.id, title: goals.title }).from(goals).where(eq(goals.id, goalId)).get();
 91→    if (goal) goalTitles.set(goal.id, goal.title);
 92→  }
 93→
 94→  const enrichTodo = (t: typeof todos.$inferSelect) => ({
 95→    ...t,
 96→    goalTitle: t.goalId ? (goalTitles.get(t.goalId) ?? null) : null,
 97→  });
 98→
 99→  const undoneList = [...undoneMap.values()].map(enrichTodo);
100→  const overdue = undoneList.filter((t) => t.dueDate && t.dueDate < date);
101→  const dueTodayOrNoDue = undoneList.filter((t) => !t.dueDate || t.dueDate === date);
102→
103→  return {
104→    overdue,
105→    todos: dueTodayOrNoDue,
106→    completed: completedToday.map(enrichTodo),
107→  };
108→}
109→
110→export function getTodo(db: Db, id: string) {
111→  return db.select().from(todos).where(eq(todos.id, id)).get() ?? null;
112→}
113→
114→export function createTodo(db: Db, input: unknown, eventBus?: EventBus) {
115→  const data = createTodoSchema.parse(input);
116→  const id = nanoid();
117→  const now = new Date().toISOString();
118→
119→  if (data.goalId) {
120→    const goal = db.select().from(goals).where(eq(goals.id, data.goalId)).get();
121→    if (!goal) throw new Error('Goal not found');
122→  }
123→
124→  db.insert(todos)
125→    .values({
126→      id,
127→      title: data.title,
128→      note: data.note ?? null,
129→      dueDate: data.dueDate ?? null,
130→      goalId: data.goalId ?? null,
131→      createdAt: now,
132→      updatedAt: now,
133→    })
134→    .run();
135→
136→  if (data.goalId) {
137→    eventBus?.emitMutation({
138→      type: 'todo_linked',
139→      goalId: data.goalId,
140→      details: { todoId: id, todoTitle: data.title },
141→      timestamp: now,
142→    });
143→  }
144→
145→  return db.select().from(todos).where(eq(todos.id, id)).get()!;
146→}
147→
148→export function updateTodo(db: Db, id: string, input: unknown, eventBus?: EventBus) {
149→  const existing = db.select().from(todos).where(eq(todos.id, id)).get();
150→  if (!existing) return null;
151→
152→  const data = updateTodoSchema.parse(input);
153→  const now = new Date().toISOString();
154→
155→  if (data.goalId !== undefined && data.goalId !== existing.goalId) {
156→    if (existing.goalId) {
157→      eventBus?.emitMutation({
158→        type: 'todo_unlinked',
159→        goalId: existing.goalId,
160→        details: { todoId: existing.id, todoTitle: existing.title },
161→        timestamp: now,
162→      });
163→    }
164→    if (data.goalId) {
165→      const goal = db.select().from(goals).where(eq(goals.id, data.goalId)).get();
166→      if (!goal) throw new Error('Goal not found');
167→      eventBus?.emitMutation({
168→        type: 'todo_linked',
169→        goalId: data.goalId,
170→        details: { todoId: existing.id, todoTitle: data.title ?? existing.title },
171→        timestamp: now,
172→      });
173→    }
174→  }
175→
176→  const updateData: Partial<typeof todos.$inferInsert> = { updatedAt: now };
177→  if (data.title !== undefined) updateData.title = data.title;
178→  if (data.done !== undefined) updateData.done = data.done;
179→  if (data.note !== undefined) updateData.note = data.note ?? null;
180→  if (data.dueDate !== undefined) updateData.dueDate = data.dueDate ?? null;
181→  if (data.goalId !== undefined) updateData.goalId = data.goalId ?? null;
182→
183→  db.update(todos).set(updateData).where(eq(todos.id, id)).run();
184→
185→  return db.select().from(todos).where(eq(todos.id, id)).get()!;
186→}
187→
188→export function deleteTodo(db: Db, id: string, eventBus?: EventBus): boolean {
189→  const existing = db.select().from(todos).where(eq(todos.id, id)).get();
190→  if (!existing) return false;
191→
192→  if (existing.goalId) {
193→    eventBus?.emitMutation({
194→      type: 'todo_unlinked',
195→      goalId: existing.goalId,
196→      details: { todoId: existing.id, todoTitle: existing.title },
197→      timestamp: new Date().toISOString(),
198→    });
199→  }
200→
201→  db.delete(todos).where(eq(todos.id, id)).run();
202→  return true;
203→}
