 1→import { Database } from 'bun:sqlite';
 2→import { drizzle, type BunSQLiteDatabase } from 'drizzle-orm/bun-sqlite';
 3→import { mkdirSync } from 'fs';
 4→import { dirname, join } from 'path';
 5→import { homedir } from 'os';
 6→
 7→const DEFAULT_DB_PATH = join(homedir(), '.claude', 'construct', 'data', 'construct.db');
 8→
 9→export function createDb(url?: string): { db: BunSQLiteDatabase; sqlite: Database } {
10→  const dbPath = url || process.env.CONSTRUCT_DB_PATH || DEFAULT_DB_PATH;
11→  if (dbPath !== ':memory:') {
12→    mkdirSync(dirname(dbPath), { recursive: true });
13→  }
14→  const sqlite = new Database(dbPath);
15→  sqlite.exec('PRAGMA journal_mode = WAL');
16→  sqlite.exec('PRAGMA foreign_keys = ON');
17→  const db = drizzle(sqlite);
18→  return { db, sqlite };
19→}
20→
21→export type Db = BunSQLiteDatabase;
22→export type Sqlite = Database;
